#include <stdio.h>
int main() {
    int T, H;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &H);
        if (H < 8) printf("LESS\n");
        else if (H == 8) printf("PERFECT\n");
        else printf("MORE\n");
    }
    return 0;
}

